  "integration_assessment": {
    "component_interactions": [
      {
        "from": "Upstream Caller",
        "to": "Order Enrichment Service",
        "status": "broken",
        "issue": "Inbound timeout of 500ms is mathematically impossible to satisfy. Sequential downstream p99 sum is 1150ms (200+150+800). Even if calls were parallelized, InventoryService p99 alone (800ms) exceeds the 500ms budget. This service will timeout on the majority of requests under load."
      },
      {
        "from": "Order Enrichment Service",
        "to": "ProductService",
        "status": "risk",
        "issue": "Outbound timeout of 1000ms is 5x the p99 (200ms). Acceptable individually but irrelevant given the inbound timeout is only 500ms — the upstream caller has already disconnected."
      },
      {
        "from": "Order Enrichment Service",
        "to": "CustomerService",
        "status": "risk",
        "issue": "Outbound timeout of 1000ms is 6.7x the p99 (150ms). Same orphaned-work problem as ProductService."
      },
      {
        "from": "Order Enrichment Service",
        "to": "InventoryService",
        "status": "broken",
        "issue": "InventoryService p99 (800ms) alone exceeds the inbound timeout (500ms). Even as the sole call this would fail at p99. Outbound timeout of 1000ms means the service will burn resources on a call whose result can never be delivered to the upstream caller."
      }
    ],
    "contract_compliance": "VIOLATED. The service cannot meet its implicit SLA with the upstream caller. The inbound 500ms timeout is a hard contract, and the downstream call chain cannot satisfy it under any realistic latency distribution.",
    "data_flow_integrity": "Under timeout conditions, the upstream caller receives an error or empty response. The enrichment service may still be executing downstream calls (orphaned work), wasting resources and potentially causing downstream load amplification with no benefit."
  },

  "observability_review": {
    "logging": {
      "coverage": "gaps",
      "gaps": [
        "No mention of logging when inbound timeout is breached — the on-call engineer needs to see 'upstream disconnected after 500ms, downstream calls still in-flight' to diagnose the core problem",
        "No logging of partial enrichment results — if 2 of 3 calls succeed before timeout, that context is lost",
        "No correlation ID propagation to downstream services for distributed tracing"
      ]
    },
    "metrics": {
      "coverage": "gaps",
      "gaps": [
        "No per-downstream-service latency histogram (e.g. enrichment_downstream_duration{service=inventory}). Cannot isolate which dependency is causing timeouts without this.",
        "No metric for orphaned/wasted work — requests where upstream already timed out but downstream calls continued",
        "No metric for timeout rate vs error rate distinction (enrichment_failed_total conflates timeouts, 5xx, connection refused)",
        "No metric for enrichment completeness (full vs partial vs empty enrichment)"
      ]
    },
    "tracing": {
      "coverage": "gaps",
      "gaps": [
        "No distributed tracing mentioned. With three downstream services, a trace with spans per call is essential for latency debugging.",
        "Request ID in logs is a start but does not replace proper trace context propagation (W3C traceparent or similar)"
      ]
    },
    "debugging_capability": "Partial. Request ID and per-call duration logging is good for single-request debugging. However, the absence of per-service latency histograms and trace propagation means diagnosing systemic latency issues (which WILL occur given the timeout math) requires log aggregation and manual correlation. At 3am, the on-call engineer will see enrichment_failed_total spiking but will not be able to quickly attribute it to InventoryService latency vs a network issue vs the inbound timeout mismatch."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "InventoryService latency at p99 (800ms)",
        "handling": "unhandled",
        "recommendation": "CRITICAL: This is not an edge case — it is the expected p99 behavior. The service will fail on every request where InventoryService hits p99. Options: (1) parallelize all three calls to reduce total latency to max(200,150,800)=800ms, (2) negotiate a higher inbound timeout (>800ms), (3) implement graceful degradation — return partial enrichment without inventory data if it exceeds a budget, (4) some combination of all three."
      },
      {
        "scenario": "Normal operation under moderate load",
        "handling": "unhandled",
        "recommendation": "CRITICAL: Sequential p50 latencies likely sum to ~300-500ms, putting even median requests at risk of breaching the 500ms inbound timeout. This is not a tail-latency problem — it is a design problem."
      },
      {
        "scenario": "One downstream service is completely down",
        "handling": "unhandled",
        "recommendation": "No circuit breaker means every request will wait up to 1000ms for a dead service, guaranteeing inbound timeout. Implement circuit breakers to fail fast (e.g. 50ms) when a downstream is unhealthy, and return partial enrichment."
      },
      {
        "scenario": "Upstream caller times out at 500ms, downstream calls continue",
        "handling": "unhandled",
        "recommendation": "Implement context/deadline propagation. When the inbound context is cancelled, abort in-flight downstream calls immediately to avoid orphaned work and resource waste."
      },
      {
        "scenario": "InventoryService degraded (elevated latency but not down)",
        "handling": "unhandled",
        "recommendation": "This is the most likely production incident. Without circuit breakers or adaptive timeouts, the enrichment service will accumulate threads/connections waiting on InventoryService, potentially exhausting its own connection pool and cascading failure to ProductService and CustomerService calls."
      },
      {
        "scenario": "Health check fails due to one downstream being unavailable",
        "handling": "partial",
        "recommendation": "Health check coupling to all three services means a single downstream outage will mark the enrichment service unhealthy, causing load balancer removal. If the service can return partial enrichment, the health check should distinguish between liveness (service process is up) and readiness (all downstreams available)."
      }
    ],
    "retry_config": "No retries configured. Acceptable given the tight timeout budget — retries would only worsen the timeout situation. However, a single fast retry on connection-refused (not timeout) for ProductService or CustomerService (low-latency services) could improve availability without significant latency cost, IF calls are parallelized first.",
