    "circuit_breakers": "None. Must-have for InventoryService given its high p99. Should trip after sustained timeout rate and return degraded enrichment.",
    "graceful_degradation": "None. The service is all-or-nothing. Must implement partial enrichment — if inventory data is unavailable or slow, return order enriched with product and customer data only, with a flag indicating incomplete enrichment."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": true,
    "rollback_plan": "Redeploy previous image. Acceptable for a stateless enrichment service with no database migrations.",
    "monitoring_coverage": "Basic counters and histogram exist but lack per-dependency granularity. Cannot diagnose which downstream is causing failures without log grep. Need per-service latency histograms and error counters.",
    "on_call_documentation": "Not mentioned. At minimum needs: (1) runbook for each downstream failure mode, (2) dashboard showing per-downstream latency and error rates, (3) escalation contacts for ProductService, CustomerService, and InventoryService teams.",
    "new_infrastructure_required": {
      "new_env_vars": [],
